var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그 누가… 우리를 막을 쏘냐…….","JPN":"誰が……我々を止めるのか……","ENG":"No one... can stop us...","TWN":"誰能……阻擋我們……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"시그마 해적단…….","JPN":"シグマ海賊団……","ENG":"The Sigma Pirates...","TWN":"西格瑪海盜團……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"예이.","JPN":"イェイ。","ENG":"Yay.","TWN":"耶……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"기운 차리세요. 그래도 보물이 섬에 없다는 것 정도는 확인했잖아요.","JPN":"元気出してください。でもお宝が島にないってことは確認できたじゃないですか。","ENG":"Cheer up. At least we know it's not on the island.","TWN":"打起精神來。至少我們確認了寶物不在島上。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아니면 모네 양 때문에 그래요? 부모님 일을 돕겠다는데 어쩌겠어요.","JPN":"それとも、モネさんのせいなんですか？　両親の仕事を手伝うっていうから仕方ないでしょう？","ENG":"Or is it because of Mone? We can't force her to join, especially since she's trying to help out her parents.","TWN":"還是說，是因為莫妮嗎？因為要幫父母的忙，有什麼辦法。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"죄송함다. 부모님 일을 도와드리느라 선장님네랑 가기는 힘들 것 같슴다.","JPN":"すみません。両親の仕事を手伝わないとっすから、船長たちと一緒には行けないっす。","ENG":"I'm sorry. I don't think I can join your journey because I have to help my parents.","TWN":"對不起，莫妮要幫忙爸爸媽媽，恐怕沒辦法和船長一起出發。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"대신 모네가 필요할 땐 언제든 연락 주십셔! 전력을 다해 도와드리겠슴다!","JPN":"その代わりに、モネが必要な時にはいつでも連絡してくださいっす！　全力で手伝うっす！","ENG":"But if you ever need Mone, let me know! I'll do my best to help, ma'am!","TWN":"但是如果需要莫妮，請隨時叫我！莫妮會盡全力幫助船長的哩！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"모에나 씨에게 그라운드 원으로 돌아갈 티켓도 받았고, 지금은 이정도로 만족하자고요.","JPN":"モエナさんからグラウンド・ワンに戻るチケットももらったし、今はこの程度でも満足しましょうよ。","ENG":"Moena gave us a ticket to get us back to Ground One, so let's focus on that.","TWN":"莫妮的媽媽也給了我們回到G1的船票，就到此為止吧？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으으. 완전체 해적단을 향한 꿈이…….","JPN":"うう。完全体の海賊団への夢が……","ENG":"Ngh. My dream of completing a whole pirate crew...","TWN":"嗚嗚。組織完整海盜團的夢想……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"실장님. 보물은 뒷전이죠?","JPN":"室長。お宝はどうでもいいんでしょう？","ENG":"The treasure isn't even your main goal, is it, Chief?","TWN":"室長，寶物是次要的，對吧？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유피유피. 크레데레가 보물을 찾았습니다.","JPN":"ユピユピ。クレデレがお宝を見つけました。","ENG":"Yuppie-yuppie. Credere found the treasure.","TWN":"悠菲、悠菲。克蕾妲莉找到寶藏了。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"보물의 정체는 최첨단 하이테크놀로지로 만들어진 정보전달모듈이었습니다.","JPN":"お宝の正体は、最先端のハイテクノロジーで作られた情報伝達モジュールでした。","ENG":"The treasure was an information transfer module created with state-of-the-art technology.","TWN":"寶藏的真面目，是這個由最尖端高科技製造的資訊傳遞模組！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"갑자기 뭔 뜬구름 잡는 소리예요? 이건 그냥 평범한 메모리 카드잖아요.","JPN":"いきなりどういうことですか？　これは普通のメモリーカードでしょう？","ENG":"What are you talking about? This is an ordinary memory card.","TWN":"突然胡說八道什麼？這不就是普通的記憶卡嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"보물 맞습니다. 가지고 있던 사람이 이것만 있으면 부자가 될 거라고 말했거든요.","JPN":"お宝に間違いありません。これを持っていた人が、これさえあればお金持ちになれるって言ってましたから。","ENG":"It is treasure. The owner said this could make us rich.","TWN":"這是寶藏沒錯。主人說只要有這個就能成為百萬富翁。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제발. 다른 사람 물건을 멋대로 가져왔다는 소리만큼은 하지 말아 주세요.","JPN":"お願いだから。人のものを勝手に持ってきましたーなんてことだけは勘弁してください。","ENG":"Please. Don't tell me you stole this from its owner.","TWN":"拜託，請不要告訴我你隨便拿了別人的東西。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"일행이 있을지 모르니 인질로 붙잡았어야 했을까요?","JPN":"仲間がいるかもしれないから、人質にした方が良かったのでしょうか？","ENG":"Should Credere have taken him hostage, since he might have had company?","TWN":"不知道對方有沒有同夥，難道克蕾妲莉應該把他當人質抓起來？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"안 됩니다, 유피. 그건 범죄라고요.","JPN":"ダメです、ユピ。それは犯罪です。","ENG":"Credere can't, Yuppie. That's illegal.","TWN":"不行，悠菲。那是犯罪。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이건 제가 맡고 있을 테니까 엉뚱한 소리 말고 가서 주인분이나 찾아오세요.","JPN":"これは私が預かっておきますから、変なこと言ってないで元の持ち主を探してきてください。","ENG":"I'll take this, so quit talking nonsense and go find the owner.","TWN":"我來拿著吧，別再胡說八道，去找那個主人吧。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"보물은 여기 없으니까, 절-대 딴 길로 새지 마시고요. 알겠죠?","JPN":"お宝はここにはないですから、絶ー対寄り道しないでください。わかりました？","ENG":"The treasure isn't here. So don't you dare stray away, okay?","TWN":"這裡沒什麼寶藏，不准再隨便亂跑，明白嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"네-엡.","JPN":"はーい。","ENG":"Yuuup.","TWN":"嗯——好的。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"들으셨습니까, 시그마. 저와 함께 이 배의 구조를 샅샅이 파헤치는 겁니다.","JPN":"聞きましたか、シグマ。私と一緒にこの船の構造を隅々まで調べるのです。","ENG":"Did you hear that, Sigma? We'll be inspecting every corner of this ship's structure together.","TWN":"聽到了嗎，西格瑪？我們一起徹底調查這艘船的結構吧。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오, 모험. 재밌겠다!","JPN":"おお、冒険。面白そう！","ENG":"Ooh, an adventure. Fun!","TWN":"噢噢，冒險，感覺好好玩！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하아… 졸지에 애가 둘이라니. 이 정도면 인사평가에 올라가야 하는 거 아닌가 몰라.","JPN":"はあ……いきなり子どもが二人になるなんて。こんなに大変なら人事評価に反映されるべきじゃない？","ENG":"*Sigh* I've got two kids now. This should be included in my performance evaluation.","TWN":"哀哀……突然變成要照顧兩個孩子，應該要幫我加分吧。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"누군가 이 노고를 알아줬으면 좋겠는데 말이지.","JPN":"誰かがこの苦労に気付いてほしいなあ。","ENG":"Someone has to recognize all this effort.","TWN":"真希望有人能理解我的辛苦……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};